// Obtener todos los items de entrada
const items = $input.all();

// Filtrar solo los mensajes de la IA
const aiMessages = items.filter(item => item.json.message?.type === 'ai');

// Si no hay mensajes de IA, devolver vacío
if (aiMessages.length === 0) {
  return [
    {
      json: {
        lastAiMessage: null
      }
    }
  ];
}

// Tomar el último mensaje de la IA
const lastAiMessage = aiMessages[aiMessages.length - 1].json.message.content;

// Devolver solo ese mensaje
return [
  {
    json: {
      lastAiMessage
    }
  }
];

